+{
+    ros::AdvertiseOptions opts;
+    opts.init<M>(topic, queue_size,
+            [this](const ros::SingleSubscriberPublisher&)
+            {
+                this->update_subscriber_state();
+            },
+            [this](const ros::SingleSubscriberPublisher&)
+            {
+                this->update_subscriber_state();
+            }
+    );
+    opts.latch = latch;
